CREATE TABLE public.volume_thresholds (id integer NOT NULL DEFAULT nextval('volume_thresholds_id_seq'::regclass), created_at timestamp without time zone NOT NULL DEFAULT now(), acquirer_id integer NOT NULL, min_card_present_percent numeric, updated_at timestamp without time zone NOT NULL DEFAULT now(), created_by character varying, risk_tier text, is_active boolean NOT NULL DEFAULT true, name text NOT NULL, max_high_ticket numeric, requires_approved_mcc boolean NOT NULL DEFAULT false, max_monthly_volume numeric);
CREATE TABLE public.workflow_artifacts (ticket_stage_id integer, category text, file_type text NOT NULL, file_name text NOT NULL, uploaded_by character varying, artifact_type text NOT NULL, status text NOT NULL DEFAULT 'active'::text, description text, ticket_id integer NOT NULL, created_at timestamp without time zone NOT NULL DEFAULT now(), file_path text, updated_at timestamp without time zone NOT NULL DEFAULT now(), file_size integer, metadata jsonb DEFAULT '{}'::jsonb, id integer NOT NULL DEFAULT nextval('workflow_artifacts_id_seq'::regclass));
CREATE TABLE public.workflow_assignments (assigned_to_id character varying NOT NULL, notes text, assigned_at timestamp without time zone NOT NULL DEFAULT now(), id integer NOT NULL DEFAULT nextval('workflow_assignments_id_seq'::regclass), assigned_by_id character varying, is_active boolean NOT NULL DEFAULT true, ticket_id integer NOT NULL, unassigned_at timestamp without time zone, assignment_type text NOT NULL DEFAULT 'primary'::text);
CREATE TABLE public.workflow_definitions (is_active boolean NOT NULL DEFAULT true, entity_type text NOT NULL, updated_at timestamp without time zone NOT NULL DEFAULT now(), created_at timestamp without time zone NOT NULL DEFAULT now(), code character varying NOT NULL, description text, created_by character varying, version text NOT NULL DEFAULT '1.0'::text, name text NOT NULL, initial_status text NOT NULL DEFAULT 'submitted'::text, configuration jsonb DEFAULT '{}'::jsonb, category text NOT NULL, id integer NOT NULL DEFAULT nextval('workflow_definitions_id_seq'::regclass), final_statuses ARRAY NOT NULL DEFAULT ARRAY['approved'::text, 'declined'::text, 'withdrawn'::text]);
CREATE TABLE public.workflow_issues (issue_code character varying NOT NULL, issue_type text NOT NULL, created_at timestamp without time zone NOT NULL DEFAULT now(), resolved_by character varying, resolution text, status text NOT NULL DEFAULT 'open'::text, affected_entity text, override_reason text, overridden_by character varying, severity text NOT NULL DEFAULT 'medium'::text, score_impact integer, ticket_id integer NOT NULL, affected_entity_id text, updated_at timestamp without time zone NOT NULL DEFAULT now(), overridden_at timestamp without time zone, id integer NOT NULL DEFAULT nextval('workflow_issues_id_seq'::regclass), source_data jsonb, resolved_at timestamp without time zone, ticket_stage_id integer, description text, title text NOT NULL, affected_field text);
CREATE TABLE public.workflow_notes (ticket_id integer NOT NULL, is_internal boolean NOT NULL DEFAULT true, note_type text NOT NULL DEFAULT 'general'::text, created_at timestamp without time zone NOT NULL DEFAULT now(), updated_at timestamp without time zone NOT NULL DEFAULT now(), created_by character varying NOT NULL, ticket_stage_id integer, content text NOT NULL, id integer NOT NULL DEFAULT nextval('workflow_notes_id_seq'::regclass));
CREATE TABLE public.workflow_stages (id integer NOT NULL DEFAULT nextval('workflow_stages_id_seq'::regclass), issue_blocks_severity text, updated_at timestamp without time zone NOT NULL DEFAULT now(), auto_advance boolean NOT NULL DEFAULT true, stage_type text NOT NULL DEFAULT 'automated'::text, handler_key text, name text NOT NULL, created_at timestamp without time zone NOT NULL DEFAULT now(), is_required boolean NOT NULL DEFAULT true, requires_review boolean NOT NULL DEFAULT false, configuration jsonb DEFAULT '{}'::jsonb, workflow_definition_id integer NOT NULL, retry_config jsonb, is_active boolean NOT NULL DEFAULT true, description text, code character varying NOT NULL, timeout_minutes integer, order_index integer NOT NULL);
CREATE TABLE public.workflow_tasks (title text NOT NULL, id integer NOT NULL DEFAULT nextval('workflow_tasks_id_seq'::regclass), completed_by character varying, ticket_id integer NOT NULL, assigned_at timestamp without time zone, assigned_to_role text, completion_notes text, task_type text NOT NULL DEFAULT 'action'::text, issue_id integer, assigned_to_id character varying, created_by character varying, description text, status text NOT NULL DEFAULT 'pending'::text, completed_at timestamp without time zone, due_at timestamp without time zone, priority text NOT NULL DEFAULT 'normal'::text, updated_at timestamp without time zone NOT NULL DEFAULT now(), created_at timestamp without time zone NOT NULL DEFAULT now());
CREATE TABLE public.workflow_ticket_stages (review_notes text, execution_count integer NOT NULL DEFAULT 0, ticket_id integer NOT NULL, last_executed_at timestamp without time zone, reviewed_at timestamp without time zone, result text, updated_at timestamp without time zone NOT NULL DEFAULT now(), error_message text, last_executed_by character varying, stage_id integer NOT NULL, handler_response jsonb, reviewed_by character varying, id integer NOT NULL DEFAULT nextval('workflow_ticket_stages_id_seq'::regclass), started_at timestamp without time zone, review_decision text, status text NOT NULL DEFAULT 'pending'::text, created_at timestamp without time zone NOT NULL DEFAULT now(), completed_at timestamp without time zone);
CREATE TABLE public.workflow_tickets (completed_at timestamp without time zone, created_at timestamp without time zone NOT NULL DEFAULT now(), submitted_at timestamp without time zone NOT NULL DEFAULT now(), review_count integer NOT NULL DEFAULT 0, workflow_definition_id integer NOT NULL, current_stage_id integer, ticket_number character varying NOT NULL, last_reviewed_at timestamp without time zone, id integer NOT NULL DEFAULT nextval('workflow_tickets_id_seq'::regclass), status text NOT NULL DEFAULT 'submitted'::text, priority text NOT NULL DEFAULT 'normal'::text, assigned_to_id character varying, last_reviewed_by character varying, started_at timestamp without time zone, risk_level text, sub_status text, updated_at timestamp without time zone NOT NULL DEFAULT now(), due_at timestamp without time zone, assigned_at timestamp without time zone, entity_type text NOT NULL, risk_score integer, entity_id integer NOT NULL, metadata jsonb DEFAULT '{}'::jsonb);
CREATE TABLE public.workflow_transitions (to_value text, ticket_id integer NOT NULL, reason text, from_value text, triggered_by_system boolean NOT NULL DEFAULT false, to_stage_id integer, transition_type text NOT NULL, triggered_by character varying, notes text, created_at timestamp without time zone NOT NULL DEFAULT now(), from_stage_id integer, id integer NOT NULL DEFAULT nextval('workflow_transitions_id_seq'::regclass));